// Worked focus: httpsts-jwks-rotation-cache — Bound JWKS retrieval, issuer mapping, cache lifetime, refresh, key rotation, key identifiers, algorithm confusion, stale behavior, and outage response.
// Evidence: httpsts-worked-http-server-ts-authentication-sessions-jose-2
// Competency: httpsts-worked-http-server-ts-authentication-sessions-jose-2.
// Case 7417: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: remove one trusted proxy hop and recompute authority from the socket boundary.
function worked_http_server_ts_authentication_sessions_jose_2(issuerOk: boolean, audienceOk: boolean, expiresInSeconds: number, sessionRotated: boolean): { principal: string; accepted: boolean } {
  const claimsValid = issuerOk && audienceOk && expiresInSeconds > 0 && expiresInSeconds <= 3600;
  if (!claimsValid) return { principal: "anonymous", accepted: false };
  if (!sessionRotated) return { principal: "stale-session", accepted: false };
  return { principal: "member", accepted: true };
}

